package agent

import (
	"bytes"
	"encoding/json"
	"fmt"
	"io"
	"log"
	"net/http"
	"self-agent/common"
	"self-agent/config"
	"self-agent/model"
	"self-agent/skill"

	"github.com/samber/lo"
)

// Agent AI代理
type Agent struct {
	APIKey    string
	BaseURL   string
	Tools     []model.ToolDefinition
	Estimator *common.TokenEstimator
}

// NewAgent 创建新的Agent实例
func NewAgent(apiKey string) *Agent {
	a := &Agent{
		APIKey:    apiKey,
		BaseURL:   "https://api.deepseek.com/v1/chat/completions",
		Estimator: &common.TokenEstimator{},
	}
	// 注册可用的工具
	a.registerTools()
	return a
}

// registerTools 注册LLM可用的工具
func (a *Agent) registerTools() {
	a.Tools = []model.ToolDefinition{
		skill.ExecShellSkillDesc(),
	}
}

// SingleAsk 向Deepseek API提问（单轮对话）
func (a *Agent) SingleAsk(question string, prompt string) (string, error) {
	messages := []model.AgentMessage{
		{
			Role:    "user",
			Content: question,
		},
		{
			Role:    "system",
			Content: prompt,
		},
	}

	log.Printf("提问: %s", question)
	resp, err := a.callAPI(messages)
	if err != nil {
		return "", err
	}
	log.Printf("回答: %s", resp.Choices[0].Message.Content)
	return resp.Choices[0].Message.Content, nil
}

// Ask 向Deepseek API提问（支持function calling多轮对话）
func (a *Agent) Ask(messages []model.AgentMessage) ([]model.AgentMessage, error) {
	// 多轮tool调用循环，最多10轮防止无限循环
	for i := 0; i < 10; i++ {
		// 优先检查messages所需token，如果超过则进行压缩
		maxToken := getSystemMaxToken()
		needToken := a.Estimator.ComputeTokens(messages)
		log.Printf("当前消息所需token: %d, 最大token: %d", needToken, maxToken)
		if needToken >= maxToken {
			compressor := &Compressor{a}
			compressMessages, err := compressor.CompressMessages(messages, maxToken)
			if err != nil {
				return nil, fmt.Errorf("压缩消息失败: %v", err)
			}
			tokenAfterCompresss := a.Estimator.ComputeTokens(compressMessages)
			if tokenAfterCompresss > maxToken {
				return []model.AgentMessage{
					{
						Role:    "assistant",
						Content: "token超过限制，无法继续对话",
					},
				}, nil
			}
			log.Printf("压缩后剩余token: %d", a.Estimator.ComputeTokens(compressMessages))
			messages = compressMessages
		}
		resp, err := a.callAPI(messages)
		if err != nil {
			return nil, err
		}
		if len(resp.Choices) == 0 {
			return nil, fmt.Errorf("API返回空响应")
		}
		choice := resp.Choices[0]
		// 如果LLM没有调用工具，说明已经得出最终回复
		if choice.FinishReason != "tool_calls" || len(choice.Message.ToolCalls) == 0 {
			messages = append(messages, model.AgentMessage{
				Role:    "assistant",
				Content: choice.Message.Content,
			})
			return messages, nil
		}
		// LLM请求调用工具，将assistant消息加入上下文
		messages = append(messages, model.AgentMessage{
			Role:      "assistant",
			Content:   choice.Message.Content,
			ToolCalls: choice.Message.ToolCalls,
		})
		// 执行每个工具调用，将结果作为tool消息加入上下文
		for _, toolCall := range choice.Message.ToolCalls {
			toolResult := a.executeTool(toolCall)
			messages = append(messages, model.AgentMessage{
				Role:       "tool",
				Content:    toolResult,
				ToolCallID: toolCall.ID,
			})
		}

		log.Printf("第%d轮tool调用完成，继续请求LLM...", i+1)
	}
	return messages, fmt.Errorf("工具调用轮次超过上限")
}

func getSystemMaxToken() int64 {
	return lo.Min([]int64{
		config.GetConfig().Deepseek.MaxTokens,
		config.GetConfig().Server.MaxTokens,
	})
}

// callAPI 调用Deepseek API
func (a *Agent) callAPI(messages []model.AgentMessage) (*model.AgentResponseWithTools, error) {
	requestBody := model.AgentRequestWithTools{
		Messages:  messages,
		Model:     "deepseek-chat",
		MaxTokens: 4096,
		Tools:     a.Tools,
	}

	jsonData, err := json.Marshal(requestBody)
	if err != nil {
		return nil, fmt.Errorf("序列化请求体失败: %v", err)
	}

	req, err := http.NewRequest("POST", a.BaseURL, bytes.NewBuffer(jsonData))
	if err != nil {
		return nil, fmt.Errorf("创建请求失败: %v", err)
	}

	req.Header.Set("Content-Type", "application/json")
	req.Header.Set("Authorization", "Bearer "+a.APIKey)

	client := &http.Client{}
	resp, err := client.Do(req)
	if err != nil {
		return nil, fmt.Errorf("发送请求失败: %v", err)
	}
	defer resp.Body.Close()

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, fmt.Errorf("读取响应失败: %v", err)
	}

	if resp.StatusCode != http.StatusOK {
		return nil, fmt.Errorf("API请求失败: %s, 响应: %s", resp.Status, string(body))
	}

	var apiResp model.AgentResponseWithTools
	if err := json.Unmarshal(body, &apiResp); err != nil {
		return nil, fmt.Errorf("解析响应失败: %v", err)
	}

	return &apiResp, nil
}

// executeTool 根据工具调用请求执行对应的工具
func (a *Agent) executeTool(toolCall model.ToolCall) string {
	switch toolCall.Function.Name {
	case "exec_shell":
		return a.executeShellTool(toolCall.Function.Arguments)
	default:
		return fmt.Sprintf("未知工具: %s", toolCall.Function.Name)
	}
}

// executeShellTool 执行shell命令工具
func (a *Agent) executeShellTool(argsJSON string) string {
	var args struct {
		Command string `json:"command"`
		Timeout int    `json:"timeout"`
	}
	if err := json.Unmarshal([]byte(argsJSON), &args); err != nil {
		return fmt.Sprintf("解析工具参数失败: %v", err)
	}

	if args.Timeout <= 0 {
		args.Timeout = 30
	}
	if args.Timeout > 120 {
		args.Timeout = 120
	}

	log.Printf("执行shell命令: %s (超时: %ds)", args.Command, args.Timeout)
	result := skill.ExecShell(args.Command, args.Timeout)
	return result.FormatResult()
}

package agent

import (
	"bytes"
	"fmt"
	"log"
	"self-agent/model"

	"github.com/samber/lo"
)

const (
	dialogStartIdx       = 1
	defaultReserveDialog = 3
)

// Compressor 压缩器
type Compressor struct {
	Agent *Agent
}

// CompressMessages 消息压缩
func (c *Compressor) CompressMessages(messages []model.AgentMessage, maxToken int64) ([]model.AgentMessage, error) {
	// 筛选出三轮对话之前的信息,找到要压缩的位置idx，小于idx的所有信息都要进行压缩
	compressIdx := findCompressEndIds(messages)
	if compressIdx < dialogStartIdx {
		// 会话不足三轮，直接清空上下文，仅保留最后一轮对话
		log.Printf("对话不足三轮，直接清空上下文，仅保留最后一轮对话，messages: %v", getSystemPromptAndLatestDialog(messages))
		return getSystemPromptAndLatestDialog(messages), nil
	}
	availableToken := c.computeAvailableToken(maxToken, messages[compressIdx:])
	if availableToken <= 0 {
		// token不够，直接清空上下文，仅保留最后一轮对话
		log.Printf("token不够，直接清空上下文，仅保留最后一轮对话，messages: %v", getSystemPromptAndLatestDialog(messages))
		return getSystemPromptAndLatestDialog(messages), nil
	}
	rawMessages := messages[dialogStartIdx:compressIdx]
	// 调用LLM对消息进行压缩
	var msgMerged bytes.Buffer
	for _, message := range rawMessages {
		msgMerged.WriteString(fmt.Sprintf("%s:%s\n", message.Role, message.Content))
	}
	prompt := fmt.Sprintf("请你站在system的视角，帮我提取、总结一下当前的内容，尽量保留决策、结论。保证文本的token不超过%d", availableToken)
	compressedMessage, err := c.Agent.SingleAsk(msgMerged.String(), prompt)
	if err != nil {
		// LLM压缩失败，直接清空上下文，仅保留最后一轮对话
		log.Printf("LLM压缩失败，直接清空上下文，仅保留最后一轮对话，err: %v", err)
		return getSystemPromptAndLatestDialog(messages), nil
	}
	handledMessage := lo.Concat(messages[0:dialogStartIdx], []model.AgentMessage{{Role: "user", Content: compressedMessage}}, messages[compressIdx:])
	return handledMessage, nil
}

// findCompressEndIds 找到压缩的终点位置，即三轮对话之前的位置or0
func findCompressEndIds(messages []model.AgentMessage) int32 {
	var (
		userIdx     int32
		compressIdx int32
	)
	for i := range messages {
		message := messages[len(messages)-i-1]
		if message.Role == "user" {
			userIdx++
		}
		if userIdx == defaultReserveDialog {
			compressIdx = int32(len(messages) - i - 1)
			break
		}
	}
	return compressIdx
}

func getSystemPromptAndLatestDialog(messages []model.AgentMessage) []model.AgentMessage {
	for i := range messages {
		if messages[len(messages)-i-1].Role == "user" {
			return append(messages[:dialogStartIdx], messages[len(messages)-i-1:]...)
		}
	}
	return []model.AgentMessage{}
}

// computeAvailableToken 计算可用的token, 保留70%
func (c *Compressor) computeAvailableToken(token int64, messages []model.AgentMessage) int64 {
	return lo.Max([]int64{(token*7)/10 - c.Agent.Estimator.ComputeTokens(messages), 0})
}

