package agent

import (
	"bytes"
	"encoding/json"
	"fmt"
	"io"
	"log"
	"net/http"
	"os"
	"self-agent/common"
	"self-agent/config"
	"self-agent/model"
	"self-agent/skill"
	"strings"

	"github.com/samber/lo"
)

// Agent AI代理
type Agent struct {
	APIKey  string
	BaseURL string
	Tools   []model.ToolDefinition
}

// NewAgent 创建新的Agent实例
func NewAgent(apiKey string) *Agent {
	a := &Agent{
		APIKey:  apiKey,
		BaseURL: "https://api.deepseek.com/v1/chat/completions",
	}
	// 注册可用的工具
	a.registerTools()
	return a
}

// registerTools 注册LLM可用的工具
func (a *Agent) registerTools() {
	a.Tools = []model.ToolDefinition{
		skill.ExecShellSkillDesc(),
	}
}

// SingleAsk 向Deepseek API提问（单轮对话）
func (a *Agent) SingleAsk(question string) (string, error) {
	messages := []model.AgentMessage{
		{
			Role:    "user",
			Content: question,
		},
		{
			Role:    "system",
			Content: "帮我提取、总结一下当前的内容，尽量保留决策、结论。字数尽量精简到原来的三分之一",
		},
	}
	resp, err := a.callAPI(messages)
	if err != nil {
		return "", err
	}
	return resp.Choices[0].Message.Content, nil
}

// Ask 向Deepseek API提问（支持function calling多轮对话）
func (a *Agent) Ask(question string) (string, error) {
	// 构建系统提示词
	file, err := os.ReadFile("./prompt/system_prompt.md")
	if err != nil {
		return "", fmt.Errorf("读取系统提示词失败: %v", err)
	}

	// 构建消息列表
	messages := []model.AgentMessage{
		{
			Role:    "system",
			Content: string(file),
		},
		{
			Role:    "user",
			Content: question,
		},
	}

	// 多轮tool调用循环，最多10轮防止无限循环
	for i := 0; i < 10; i++ {
		// 优先检查messages所需token，如果超过则进行压缩
		if computeTokens(messages) >= getSystemMaxToken() {

		}
		resp, err := a.callAPI(messages)
		if err != nil {
			return "", err
		}

		if len(resp.Choices) == 0 {
			return "", fmt.Errorf("API返回空响应")
		}

		choice := resp.Choices[0]

		// 如果LLM没有调用工具，说明已经得出最终回复
		if choice.FinishReason != "tool_calls" || len(choice.Message.ToolCalls) == 0 {
			return choice.Message.Content, nil
		}

		// LLM请求调用工具，将assistant消息加入上下文
		messages = append(messages, model.AgentMessage{
			Role:      "assistant",
			Content:   choice.Message.Content,
			ToolCalls: choice.Message.ToolCalls,
		})

		// 执行每个工具调用，将结果作为tool消息加入上下文
		for _, toolCall := range choice.Message.ToolCalls {
			toolResult := a.executeTool(toolCall)
			messages = append(messages, model.AgentMessage{
				Role:       "tool",
				Content:    toolResult,
				ToolCallID: toolCall.ID,
			})
		}

		log.Printf("第%d轮tool调用完成，继续请求LLM...", i+1)
	}

	return "", fmt.Errorf("工具调用轮次超过上限")
}

func computeTokens(messages []model.AgentMessage) int64 {
	// 获取每个message的content
	builder := strings.Builder{}
	for _, message := range messages {
		builder.WriteString(message.Content)
	}
	estimator := common.TokenEstimator{}
	tokens := estimator.EstimateTokens(builder.String())
	return tokens
}

func getSystemMaxToken() int64 {
	return lo.Max([]int64{
		config.GetConfig().Deepseek.MaxTokens,
		config.GetConfig().Server.MaxTokens,
	})
}

// callAPI 调用Deepseek API
func (a *Agent) callAPI(messages []model.AgentMessage) (*model.AgentResponseWithTools, error) {
	requestBody := model.AgentRequestWithTools{
		Messages:  messages,
		Model:     "deepseek-chat",
		MaxTokens: 4096,
		Tools:     a.Tools,
	}

	jsonData, err := json.Marshal(requestBody)
	if err != nil {
		return nil, fmt.Errorf("序列化请求体失败: %v", err)
	}

	req, err := http.NewRequest("POST", a.BaseURL, bytes.NewBuffer(jsonData))
	if err != nil {
		return nil, fmt.Errorf("创建请求失败: %v", err)
	}

	req.Header.Set("Content-Type", "application/json")
	req.Header.Set("Authorization", "Bearer "+a.APIKey)

	client := &http.Client{}
	resp, err := client.Do(req)
	if err != nil {
		return nil, fmt.Errorf("发送请求失败: %v", err)
	}
	defer resp.Body.Close()

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, fmt.Errorf("读取响应失败: %v", err)
	}

	if resp.StatusCode != http.StatusOK {
		return nil, fmt.Errorf("API请求失败: %s, 响应: %s", resp.Status, string(body))
	}

	var apiResp model.AgentResponseWithTools
	if err := json.Unmarshal(body, &apiResp); err != nil {
		return nil, fmt.Errorf("解析响应失败: %v", err)
	}

	return &apiResp, nil
}

// executeTool 根据工具调用请求执行对应的工具
func (a *Agent) executeTool(toolCall model.ToolCall) string {
	switch toolCall.Function.Name {
	case "exec_shell":
		return a.executeShellTool(toolCall.Function.Arguments)
	default:
		return fmt.Sprintf("未知工具: %s", toolCall.Function.Name)
	}
}

// executeShellTool 执行shell命令工具
func (a *Agent) executeShellTool(argsJSON string) string {
	var args struct {
		Command string `json:"command"`
		Timeout int    `json:"timeout"`
	}
	if err := json.Unmarshal([]byte(argsJSON), &args); err != nil {
		return fmt.Sprintf("解析工具参数失败: %v", err)
	}

	if args.Timeout <= 0 {
		args.Timeout = 30
	}
	if args.Timeout > 120 {
		args.Timeout = 120
	}

	log.Printf("执行shell命令: %s (超时: %ds)", args.Command, args.Timeout)
	result := skill.ExecShell(args.Command, args.Timeout)
	return result.FormatResult()
}

package session

import (
	"fmt"
	"log"
	"os"
	"self-agent/agent"
	"self-agent/channel"
	"self-agent/config"
	"self-agent/model"
)

// Session 会话
type Session struct {
	ID      string
	Tasks   *model.TaskQueue
	Agent   *agent.Agent
	Channel *channel.Channel     // 绑定渠道(非必填)
	History []model.AgentMessage // 会话消息（上下文记录）
}

// NewSession 创建会话
func NewSession(id string, apiKey string) *Session {
	sessionObj := &Session{
		ID:      id,
		Tasks:   model.NewTaskQueue(),
		Agent:   agent.NewAgent(apiKey),
		History: []model.AgentMessage{},
	}
	var channelObj *channel.Channel
	cfg := config.GetConfig()
	if id == "feishu" && cfg.HasFeishuConfig() {
		channelObj = channel.NewChannel(id, channel.ChannelTypeFeishu, cfg.Channel, func(id string, content string) {
			sessionObj.Tasks.AddTask(model.Task{
				Content: content,
			})
		})
	}
	sessionObj.SetChannel(channelObj)

	// 系统提示词注入
	// 构建系统提示词
	file, err := os.ReadFile("./prompt/system_prompt.md")
	if err != nil {
		log.Printf("Error reading file: %s", err)
	} else {
		sessionObj.History = append(sessionObj.History, model.AgentMessage{
			Role:    "system",
			Content: string(file),
		})
	}
	return sessionObj
}

// SetChannel 为会话设置渠道
func (s *Session) SetChannel(ch *channel.Channel) {
	s.Channel = ch
}

// SendToChannel 通过绑定的渠道发送消息
func (s *Session) SendToChannel(message string) error {
	if s.Channel == nil {
		return nil // 没有绑定渠道，静默返回
	}
	return s.Channel.SendMessage(message)
}

// HasChannel 检查会话是否绑定了渠道
func (s *Session) HasChannel() bool {
	return s.Channel != nil
}

// Start 开始会话
func (s *Session) Start() {
	for {
		// 构建好会话上下文
		s.History = append(s.History, model.AgentMessage{
			Role:    "user",
			Content: s.Tasks.GetTask().Content,
		})
		// 发送给对应的Agent
		handledMsgs, err := s.Agent.Ask(s.History)
		if err != nil {
			fmt.Println("Error:", err)
			continue
		}
		s.History = handledMsgs
		// 将结果发送到绑定的渠道
		// TODO：这里要是没有绑定的渠道就不应该给它创建session，或者默认渠道就是console
		latestMsg := getLastMsg(s.History)
		if s.HasChannel() {
			if err := s.SendToChannel(latestMsg); err != nil {
				fmt.Println("Send to channel error:", err)
			}
		}
		fmt.Printf("Agent response: %s\n", latestMsg)
	}
}

func getLastMsg(messages []model.AgentMessage) string {
	return messages[len(messages)-1].Content
}

// Init 初始化会话
func (s *Session) Init() error {
	if err := s.Channel.Init(); err != nil {
		return err
	}
	return nil
}

package channel

import (
	"context"
	"encoding/json"
	"fmt"
	"self-agent/config"
	"self-agent/model"
	"time"

	lark "github.com/larksuite/oapi-sdk-go/v3"
	larkcore "github.com/larksuite/oapi-sdk-go/v3/core"
	larkevent "github.com/larksuite/oapi-sdk-go/v3/event"
	"github.com/larksuite/oapi-sdk-go/v3/event/dispatcher"
	larkim "github.com/larksuite/oapi-sdk-go/v3/service/im/v1"
	larkws "github.com/larksuite/oapi-sdk-go/v3/ws"
)

// ChannelType 渠道类型
type ChannelType string

const (
	ChannelTypeFeishu   ChannelType = "feishu"   // 飞书机器人
	ChannelTypeWechat   ChannelType = "wechat"   // 微信机器人
	ChannelTypeDingtalk ChannelType = "dingtalk" // 钉钉机器人
)

// Channel 渠道
type Channel struct {
	ID         string      `json:"id"`
	Type       ChannelType `json:"type"`
	AppID      string      `json:"app_id"`
	WebhookURL string      `json:"webhook_url"`
	Secret     string      `json:"secret,omitempty"`
	IsActive   bool        `json:"is_active"`
	CreatedAt  time.Time   `json:"created_at"`
	LastUsedAt time.Time   `json:"last_used_at"`

	// SessionCallback 会话回调
	SessionCallback func(string, string)
}

// FeishuMessage 飞书消息结构
type FeishuMessage struct {
	MsgType string `json:"msg_type"`
	Content struct {
		Text string `json:"text"`
	} `json:"content"`
}

// NewChannel 创建渠道
func NewChannel(id string, channelType ChannelType, cfg config.ChannelCfg, sessionCallback func(string, string)) *Channel {
	var (
		appID      string
		webhookURL string
		secret     string
	)
	switch channelType {
	case ChannelTypeFeishu:
		appID = cfg.Feishu.AppID
		webhookURL = cfg.Feishu.Webhook
		secret = cfg.Feishu.Secret
	}
	return &Channel{
		ID:              id,
		AppID:           appID,
		Type:            channelType,
		WebhookURL:      webhookURL,
		Secret:          secret,
		IsActive:        true,
		CreatedAt:       time.Now(),
		LastUsedAt:      time.Now(),
		SessionCallback: sessionCallback,
	}
}

// Init 初始化
func (c *Channel) Init() error {
	if c.Type == ChannelTypeFeishu {
		go func() {
			// 注册事件回调，OnP2MessageReceiveV1 为接收消息 v2.0；OnCustomizedEvent 内的 message 为接收消息 v1.0。
			eventHandler := dispatcher.NewEventDispatcher("", "").
				OnP2MessageReceiveV1(func(ctx context.Context, event *larkim.P2MessageReceiveV1) error {
					if event == nil {
						return nil
					}
					var eventData model.FeishuEventData
					_ = json.Unmarshal(event.Body, &eventData)
					// 发送消息给所属session
					c.SessionCallback(c.ID, eventData.Event.Message.Content)
					return nil
				}).
				OnCustomizedEvent("这里填入你要自定义订阅的 event 的 key，例如 out_approval", func(ctx context.Context, event *larkevent.EventReq) error {
					fmt.Printf("[ OnCustomizedEvent access ], type: message, data: %s\n", string(event.Body))
					return nil
				})
			// 创建Client
			cli := larkws.NewClient(c.AppID, c.Secret,
				larkws.WithEventHandler(eventHandler),
				larkws.WithLogLevel(larkcore.LogLevelDebug),
			)
			// 启动客户端
			err := cli.Start(context.Background())
			if err != nil {
				panic(fmt.Errorf("failed to start larkws client: %v", err))
			}
		}()
	}
	return nil
}

// SendMessage 发送消息到渠道
func (c *Channel) SendMessage(message string) error {
	if !c.IsActive {
		return fmt.Errorf("channel %s is not active", c.ID)
	}

	switch c.Type {
	case ChannelTypeFeishu:
		return c.sendToFeishu(message)
	default:
		return fmt.Errorf("unsupported channel type: %s", c.Type)
	}
}

// sendToFeishu 发送消息到飞书机器人
func (c *Channel) sendToFeishu(message string) error {
	// 创建 Client
	client := lark.NewClient(c.AppID, c.Secret)
	// 创建请求对象
	openID := config.GetConfig().Channel.Feishu.OpenID
	req := larkim.NewCreateMessageReqBuilder().
		ReceiveIdType(`open_id`).
		Body(larkim.NewCreateMessageReqBodyBuilder().
			ReceiveId(openID).
			MsgType(`text`).
			Content(`{"text":"` + message + `"}`).
			Build()).
		Build()

	// 发起请求
	resp, err := client.Im.V1.Message.Create(context.Background(), req)

	// 处理错误
	if err != nil {
		fmt.Println(err)
		return err
	}

	// 服务端错误处理
	if !resp.Success() {
		fmt.Printf("logId: %s, error response: \n%s", resp.RequestId(), larkcore.Prettify(resp.CodeError))
		return fmt.Errorf("failed to send message: %s", resp.CodeError)
	}

	// 业务处理
	fmt.Println(larkcore.Prettify(resp))
	c.LastUsedAt = time.Now()
	return nil
}

// BindToSession 将渠道绑定到会话
func (c *Channel) BindToSession(sessionID string) string {
	return fmt.Sprintf("channel:%s:session:%s", c.ID, sessionID)
}

// Activate 激活渠道
func (c *Channel) Activate() {
	c.IsActive = true
	c.LastUsedAt = time.Now()
}

// Deactivate 停用渠道
func (c *Channel) Deactivate() {
	c.IsActive = false
}

