{"rawEvent":{"message_id":"019d1dc34a897a5394f5611eb790882c","conversation_id":"019d19b487e670fb87afc68e9fd4ad30","tool_call_id":"tooluse_JzRDtBYn4ECv1zSUT3bHR4","document":{"file_path":"/Users/weiketang/GolandProjects/self-agent/agent/agent.go","sub_content":"agent.go","sub_content_event":"open_editor","sub_content_event_value":"/Users/weiketang/GolandProjects/self-agent/agent/agent.go","sub_content_tip":"/Users/weiketang/GolandProjects/self-agent/agent/agent.go","apply_content":"package agent

import (
	"bytes"
	"encoding/json"
	"fmt"
	"io"
	"log"
	"net/http"
	"os"
	"self-agent/model"
	"self-agent/skill"
)

// Agent AI代理
type Agent struct {
	APIKey string
	BaseURL string
	Tools []model.ToolDefinition
}

// NewAgent 创建新的Agent实例
func NewAgent(apiKey string) *Agent {
	a := &Agent{
		APIKey: apiKey,
		BaseURL: "https://api.deepseek.com/v1/chat/completions",
	}
	// 注册可用的工具
	a.registerTools()
	return a
}

// registerTools 注册LLM可用的工具
func (a *Agent) registerTools() {
	a.Tools = []model.ToolDefinition{
		{
			Type: "function",
			Function: model.FunctionDefinition{
				Name: "exec_shell",
				Description: "在服务器上执行shell命令。可以用来查看文件、运行脚本、查询系统状态等。注意：命令会在服务器上真实执行，请谨慎使用。",
				Parameters: map[string]interface{}{
					"type": "object",
					"properties": map[string]interface{}{
						"command": map[string]interface{}{
							"type": "string",
							"description": "要执行的shell命令",
						},
						"timeout": map[string]interface{}{
							"type": "integer",
							"description": "命令超时时间（秒），默认30秒，最大120秒",
						},
					},
					"required": []string{"command"},
				},
			},
		},
	}
}

// Ask 向Deepseek API提问（支持function calling多轮对话）
func (a *Agent) Ask(question string) (string, error) {
	// 构建系统提示词
	file, err := os.ReadFile("./prompt/system_prompt.md")
	if err != nil {
		return "", fmt.Errorf("读取系统提示词失败: %v", err)
	}

	// 构建消息列表
	messages := []model.AgentMessage{
		{
			Role: "system",
			Content: string(file),
		},
		{
			Role: "user",
			Content: question,
		},
	}

	// 多轮tool调用循环，最多10轮防止无限循环
	for i := 0; i < 10; i++ {
		resp, err := a.callAPI(messages)
		if err != nil {
			return "", err
		}

		if len(resp.Choices) == 0 {
			return "", fmt.Errorf("API返回空响应")
		}

		choice := resp.Choices[0]

		// 如果LLM没有调用工具，说明已经得出最终回复
		if choice.FinishReason != "tool_calls" || len(choice.Message.ToolCalls) == 0 {
			return choice.Message.Content, nil
		}

		// LLM请求调用工具，将assistant消息加入上下文
		messages = append(messages, model.AgentMessage{
			Role: "assistant",
			Content: choice.Message.Content,
			ToolCalls: choice.Message.ToolCalls,
		})

		// 执行每个工具调用，将结果作为tool消息加入上下文
		for _, toolCall := range choice.Message.ToolCalls {
			toolResult := a.executeTool(toolCall)
			messages = append(messages, model.AgentMessage{
				Role: "tool",
				Content: toolResult,
				ToolCallID: toolCall.ID,
			})
		}

		log.Printf("第%d轮tool调用完成，继续请求LLM...", i+1)
	}

	return "", fmt.Errorf("工具调用轮次超过上限")
}

// callAPI 调用Deepseek API
func (a *Agent) callAPI(messages []model.AgentMessage) (*model.AgentResponseWithTools, error) {
	requestBody := model.AgentRequestWithTools{
		Messages: messages,
		Model: "deepseek-chat",
		MaxTokens: 4096,
		Tools: a.Tools,
	}

	jsonData, err := json.Marshal(requestBody)
	if err != nil {
		return nil, fmt.Errorf("序列化请求体失败: %v", err)
	}

	req, err := http.NewRequest("POST", a.BaseURL, bytes.NewBuffer(jsonData))
	if err != nil {
		return nil, fmt.Errorf("创建请求失败: %v", err)
	}

	req.Header.Set("Content-Type", "application/json")
	req.Header.Set("Authorization", "Bearer "+a.APIKey)

	client := &http.Client{}
	resp, err := client.Do(req)
	if err != nil {
		return nil, fmt.Errorf("发送请求失败: %v", err)
	}
	defer resp.Body.Close()

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, fmt.Errorf("读取响应失败: %v", err)
	}

	if resp.StatusCode != http.StatusOK {
		return nil, fmt.Errorf("API请求失败: %s, 响应: %s", resp.Status, string(body))
	}

	var apiResp model.AgentResponseWithTools
	if err := json.Unmarshal(body, &apiResp); err != nil {
		return nil, fmt.Errorf("解析响应失败: %v", err)
	}

	return &apiResp, nil
}

// executeTool 根据工具调用请求执行对应的工具
func (a *Agent) executeTool(toolCall model.ToolCall) string {
	switch toolCall.Function.Name {
	case "exec_shell":
		return a.executeShellTool(toolCall.Function.Arguments)
	default:
		return fmt.Sprintf("未知工具: %s", toolCall.Function.Name)
	}
}

// executeShellTool 执行shell命令工具
func (a *Agent) executeShellTool(argsJSON string) string {
	var args struct {
		Command string `json:"command"`
		Timeout int `json:"timeout"`
	}
	if err := json.Unmarshal([]byte(argsJSON), &args); err != nil {
		return fmt.Sprintf("解析工具参数失败: %v", err)
	}

	if args.Timeout <= 0 {
		args.Timeout = 30
	}
	if args.Timeout > 120 {
		args.Timeout = 120
	}

	log.Printf("执行shell命令: %s (超时: %ds)", args.Command, args.Timeout)
	result := skill.ExecShell(args.Command, args.Timeout)
	return result.FormatResult()
}
