				if err := json.Unmarshal([]byte(larkcore.Prettify(event)), &eventData); err != nil {
					log.Printf("Error: %v", err)
				}
				log.Printf("[ OnP2MessageReceiveV1 access ], base: %v\n", eventData)
				fmt.Printf("[ OnP2MessageReceiveV1 access ], data: %s\n", larkcore.Prettify(event))
				return nil
			})","new_string":"		OnP2MessageReceiveV1(func(ctx context.Context, event *larkim.P2MessageReceiveV1) error {
				// 直接从 event 结构体中提取数据，而非通过 Prettify 转 JSON
				eventData := model.FeishuEventData{
					EventV2Base: model.EventV2Base{
						Schema: event.Schema,
						Header: model.Header{
							EventID: event.EventV2Base.Header.EventID,
							EventType: event.EventV2Base.Header.EventType,
							AppID: event.EventV2Base.Header.AppID,
							TenantKey: event.EventV2Base.Header.TenantKey,
							CreateTime: event.EventV2Base.Header.CreateTime,
							Token: event.EventV2Base.Header.Token,
						},
					},
					Event: model.Event{
						Sender: model.Sender{
							SenderID: model.SenderID{
								OpenID: *event.Event.Sender.SenderId.OpenId,
								UnionID: *event.Event.Sender.SenderId.UnionId,
							},
							SenderType: *event.Event.Sender.SenderType,
							TenantKey: *event.Event.Sender.TenantKey,
						},
						Message: model.Message{
							MessageID: *event.Event.Message.MessageId,
							CreateTime: *event.Event.Message.CreateTime,
							UpdateTime: *event.Event.Message.UpdateTime,
							ChatID: *event.Event.Message.ChatId,
							ChatType: *event.Event.Message.ChatType,
							MessageType: *event.Event.Message.MessageType,
							Content: *event.Event.Message.Content,
						},
					},
				}
				log.Printf("[ OnP2MessageReceiveV1 access ], data: %+v\n", eventData)
