				// 直接从 SDK event 结构体字段提取数据，避免使用 Prettify（其输出不是合法 JSON）
				eventData := model.FeishuEventData{
					Schema: event.Schema,
				}
				if event.Header != nil {
					eventData.Header = model.Header{
						EventID: event.Header.EventID,
						EventType: event.Header.EventType,
						AppID: event.Header.AppID,
						TenantKey: event.Header.TenantKey,
						CreateTime: event.Header.CreateTime,
						Token: event.Header.Token,
					}
				}
				if event.Event != nil {
