{"rawEvent":{"message_id":"019ce2101b5976c1b57425281ee1e0d3","conversation_id":"019ce1d8b8ae7523841bad0f92d0fc72","tool_call_id":"call_e1c16cfb-0f1b-43b6-a680-e8716645cc71","document":{"file_path":"/Users/weiketang/GolandProjects/self-agent/agent/agent.go","sub_content":"agent.go","sub_content_event":"open_editor","sub_content_event_value":"/Users/weiketang/GolandProjects/self-agent/agent/agent.go","sub_content_tip":"/Users/weiketang/GolandProjects/self-agent/agent/agent.go","apply_content":"package agent

import (
	"bytes"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
)

// Agent AI代理
type Agent struct {
	APIKey string
	BaseURL string
}

// DeepseekResponse Deepseek API响应结构
type DeepseekResponse struct {
	Choices []struct {
		Message struct {
			Content string `json:"content"`
		} `json:"message"`
	} `json:"choices"`
}

// NewAgent 创建新的Agent实例
func NewAgent(apiKey string) *Agent {
	return &Agent{
		APIKey: apiKey,
		BaseURL: "https://api.deepseek.com/v1/chat/completions",
	}
}

// Ask 向Deepseek API提问
func (a *Agent) Ask(question string) (string, error) {
	// 构建请求体
	requestBody := map[string]interface{}{
		"model": "deepseek-chat",
		"messages": []map[string]string{
			{
				"role": "user",
				"content": question,
			},
		},
		"max_tokens": 1000,
	}

	jsonData, err := json.Marshal(requestBody)
	if err != nil {
		return "", fmt.Errorf("序列化请求体失败: %v", err)
	}

	// 创建HTTP请求
	req, err := http.NewRequest("POST", a.BaseURL, bytes.NewBuffer(jsonData))
	if err != nil {
		return "", fmt.Errorf("创建请求失败: %v", err)
	}

	req.Header.Set("Content-Type", "application/json")
	req.Header.Set("Authorization", "Bearer "+a.APIKey)

	// 发送请求
	client := &http.Client{}
	resp, err := client.Do(req)
	if err != nil {
		return "", fmt.Errorf("发送请求失败: %v", err)
	}
	defer resp.Body.Close()

	// 读取响应
	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return "", fmt.Errorf("读取响应失败: %v", err)
	}

	if resp.StatusCode != http.StatusOK {
		return "", fmt.Errorf("API请求失败: %s, 响应: %s", resp.Status, string(body))
	}

	// 解析响应
	var deepseekResp DeepseekResponse
	if err := json.Unmarshal(body, &deepseekResp); err != nil {
		return "", fmt.Errorf("解析响应失败: %v", err)
	}

	if len(deepseekResp.Choices) == 0 {
		return "", fmt.Errorf("API返回空响应")
	}

	return deepseekResp.Choices[0].Message.Content, nil
}","instruction":"创建agent包和Agent结构，实现Deepseek API的连接和问答功能","apply_mode":"apply_only"}},"timestamp":1773319249,"type":"TOOL_CALL_ARGS"}

