{"rawEvent":{"message_id":"019ce2101b5976c1b57425281ee1e0d3","conversation_id":"019ce1d8b8ae7523841bad0f92d0fc72","tool_call_id":"call_5d1c03f8-d30f-466b-94bf-5e981728363a","document":{"file_path":"/Users/weiketang/GolandProjects/self-agent/gateway/gateway.go","sub_content":"gateway.go","sub_content_event":"open_editor","sub_content_event_value":"/Users/weiketang/GolandProjects/self-agent/gateway/gateway.go","sub_content_tip":"/Users/weiketang/GolandProjects/self-agent/gateway/gateway.go","apply_content":"package gateway

import (
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"os"
	"self-agent/model"
	"self-agent/session"
	"strings"
)

// Gateway 网关
type Gateway struct {
	Sessions map[string]*session.Session
	APIKey string
}

// NewGateway 创建网关
func NewGateway() *Gateway {
	apiKey := os.Getenv("DEEPSEEK_API_KEY")
	if apiKey == "" {
		apiKey = "default-api-key" // 默认值，实际使用时需要配置环境变量
	}

	return &Gateway{
		Sessions: make(map[string]*session.Session),
		APIKey: apiKey,
	}
}

// ServeHTTP 处理http请求
func (g *Gateway) ServeHTTP(w http.ResponseWriter, r *http.Request) {
	// 获取请求req.Body中的SessionID，找到对应的Session
	body, _ := io.ReadAll(r.Body)
	var reqBody struct {
