import (
	"fmt"
	"os"
	"gopkg.in/yaml.v3"
)

// Config 应用配置结构体
type Config struct {
	Deepseek struct {
		APIKey string `yaml:"api_key"`
	} `yaml:"deepseek"`
	Server struct {
		Port int `yaml:"port"`
	} `yaml:"server"`
	Logging struct {
		Level string `yaml:"level"`
		Format string `yaml:"format"`
	} `yaml:"logging"`
}

// LoadConfig 从YAML文件加载配置
func LoadConfig() (*Config, error) {
	// 读取配置文件
	data, err := os.ReadFile("config/config.yaml")
	if err != nil {
		return nil, fmt.Errorf("读取配置文件失败: %v", err)
	}

	// 解析YAML配置
	var cfg Config
	err = yaml.Unmarshal(data, &cfg)
	if err != nil {
		return nil, fmt.Errorf("解析YAML配置失败: %v", err)
	}

	// 检查必要的配置项
	if cfg.Deepseek.APIKey == "your-deepseek-api-key-here" {
		return nil, fmt.Errorf("请配置有效的Deepseek API密钥")
	}

	return &cfg, nil
}

// LoadConfigWithDefaults 加载配置，如果失败则使用默认值
func LoadConfigWithDefaults() *Config {
	cfg, err := LoadConfig()
	if err != nil {
		fmt.Printf("配置加载失败，使用默认配置: %v\n", err)
		return &Config{
			Server: struct {
				Port int `yaml:"port"`
			}{Port: 19100},
			Logging: struct {
				Level string `yaml:"level"`
				Format string `yaml:"format"`
			}{Level: "info", Format: "text"},
		}
	}
	return cfg
}","instruction":"创建新的Go配置文件，支持从YAML文件读取配置，包含错误处理和默认值回退","apply_mode":"apply_only"}},"timestamp":1773319600,"type":"TOOL_CALL_ARGS"}

