package config

import (
	"os"
)

// Config 应用配置
type Config struct {
	DeepseekAPIKey string
	Port           string
}

// LoadConfig 加载配置
func LoadConfig() *Config {
	apiKey := os.Getenv("DEEPSEEK_API_KEY")
	if apiKey == "" {
		apiKey = "default-api-key" // 默认值，实际使用时需要配置环境变量
	}

	port := os.Getenv("PORT")
	if port == "" {
		port = "19100" // 默认端口
	}

	return &Config{
		DeepseekAPIKey: apiKey,
		Port:           port,
	}
}

