{"rawEvent":{"message_id":"019ce21b6ce1736f9d4fb6e484a9a407","conversation_id":"019ce1d8b8ae7523841bad0f92d0fc72","tool_call_id":"call_d3428a2f-280c-4a1e-8410-2d40e4608bfa","document":{"file_path":"/Users/weiketang/GolandProjects/self-agent/gateway/gateway.go","sub_content":"gateway.go","sub_content_event":"open_editor","sub_content_event_value":"/Users/weiketang/GolandProjects/self-agent/gateway/gateway.go","sub_content_tip":"/Users/weiketang/GolandProjects/self-agent/gateway/gateway.go","apply_content":"package gateway

import (
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"self-agent/channel"
	"self-agent/config"
	"self-agent/model"
	"self-agent/session"
)

// Gateway 网关
type Gateway struct {
	Sessions map[string]*session.Session
	Config *config.Config
}

// NewGateway 创建网关
func NewGateway() *Gateway {
	cfg, err := config.LoadConfig()
	if err != nil {
		// 如果配置加载失败，使用默认配置
		cfg = config.LoadConfigWithDefaults()
	}

	return &Gateway{
		Sessions: make(map[string]*session.Session),
		Config: cfg,
	}
}

// ServeHTTP 处理http请求
func (g *Gateway) ServeHTTP(w http.ResponseWriter, r *http.Request) {
	switch r.Method {
	case "POST":
		g.handlePostRequest(w, r)
	case "PUT":
		g.handlePutRequest(w, r)
	default:
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
	}
}

// handlePostRequest 处理POST请求（发送消息到AI）
func (g *Gateway) handlePostRequest(w http.ResponseWriter, r *http.Request) {
	body, _ := io.ReadAll(r.Body)
	var reqBody struct {
		ID string `json:"id"`
		Content string `json:"content"`
	}
	_ = json.Unmarshal(body, &reqBody)

	sessionKey := buildSessionKey(reqBody.ID)
	if _, ok := g.Sessions[sessionKey]; !ok {
		g.Sessions[sessionKey] = session.NewSession(reqBody.ID, g.Config.Deepseek.APIKey)
	}
	sessionObj := g.Sessions[sessionKey]

	// 将Content封装为Task，加入到session的Tasks中
	sessionObj.Tasks.AddTask(model.Task{
		Content: reqBody.Content,
	})

	// 如果有绑定的渠道，将消息发送到渠道
	if sessionObj.HasChannel() {
		_ = sessionObj.SendToChannel(fmt.Sprintf("收到新消息: %s", reqBody.Content))
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]interface{}{
		"status": "success",
		"session_id": reqBody.ID,
		"has_channel": sessionObj.HasChannel(),
	})
}

// handlePutRequest 处理PUT请求（绑定渠道）
func (g *Gateway) handlePutRequest(w http.ResponseWriter, r *http.Request) {
	body, _ := io.ReadAll(r.Body)
	var reqBody struct {
		SessionID string `json:"session_id"`
		ChannelType string `json:"channel_type"`
		WebhookURL string `json:"webhook_url"`
		Secret string `json:"secret,omitempty"`
	}
	_ = json.Unmarshal(body, &reqBody)

	sessionKey := buildSessionKey(reqBody.SessionID)
	if _, ok := g.Sessions[sessionKey]; !ok {
		g.Sessions[sessionKey] = session.NewSession(reqBody.SessionID, g.Config.Deepseek.APIKey)
	}
	sessionObj := g.Sessions[sessionKey]

	// 创建并绑定渠道
	ch := channel.NewChannel(
		fmt.Sprintf("channel-%s", reqBody.SessionID),
		channel.ChannelType(reqBody.ChannelType),
		reqBody.WebhookURL,
		reqBody.Secret,
	)
	sessionObj.SetChannel(ch)

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]interface{}{
		"status": "success",
		"session_id": reqBody.SessionID,
		"channel_id": ch.ID,
		"channel_type": ch.Type,
	})
}

func buildSessionKey(id string) string {
	return fmt.Sprintf("session:%s", id)
}","instruction":"更新gateway.go文件，支持POST请求发送消息到AI和PUT请求绑定Channel到Session，添加渠道消息转发功能","apply_mode":"apply_only"}},"timestamp":1773320018,"type":"TOOL_CALL_ARGS"}

