import (
	"bytes"
	"encoding/json"
	"fmt"
	"net/http"
	"time"
)

// ChannelType 渠道类型
type ChannelType string

const (
	ChannelTypeFeishu ChannelType = "feishu" // 飞书机器人
	ChannelTypeWechat ChannelType = "wechat" // 微信机器人
	ChannelTypeDingtalk ChannelType = "dingtalk" // 钉钉机器人
)

// Channel 渠道
type Channel struct {
	ID string `json:"id"`
	Type ChannelType `json:"type"`
	WebhookURL string `json:"webhook_url"`
	Secret string `json:"secret,omitempty"`
	IsActive bool `json:"is_active"`
	CreatedAt time.Time `json:"created_at"`
	LastUsedAt time.Time `json:"last_used_at"`
}

// FeishuMessage 飞书消息结构
type FeishuMessage struct {
	MsgType string `json:"msg_type"`
	Content struct {
		Text string `json:"text"`
	} `json:"content"`
}

// NewChannel 创建渠道
func NewChannel(id string, channelType ChannelType, webhookURL string, secret string) *Channel {
	return &Channel{
		ID: id,
		Type: channelType,
		WebhookURL: webhookURL,
		Secret: secret,
		IsActive: true,
		CreatedAt: time.Now(),
		LastUsedAt: time.Now(),
	}
}

// SendMessage 发送消息到渠道
func (c *Channel) SendMessage(message string) error {
	if !c.IsActive {
		return fmt.Errorf("channel %s is not active", c.ID)
	}

	switch c.Type {
	case ChannelTypeFeishu:
		return c.sendToFeishu(message)
	default:
		return fmt.Errorf("unsupported channel type: %s", c.Type)
	}
}

// sendToFeishu 发送消息到飞书机器人
func (c *Channel) sendToFeishu(message string) error {
	feishuMsg := FeishuMessage{
		MsgType: "text",
		Content: struct {
			Text string `json:"text"`
		}{
			Text: message,
		},
	}

	jsonData, err := json.Marshal(feishuMsg)
	if err != nil {
		return fmt.Errorf("failed to marshal feishu message: %v", err)
	}

	resp, err := http.Post(c.WebhookURL, "application/json", bytes.NewBuffer(jsonData))
	if err != nil {
		return fmt.Errorf("failed to send message to feishu: %v", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return fmt.Errorf("feishu API returned status: %d", resp.StatusCode)
	}

	c.LastUsedAt = time.Now()
	return nil
}

// BindToSession 将渠道绑定到会话
func (c *Channel) BindToSession(sessionID string) string {
	return fmt.Sprintf("channel:%s:session:%s", c.ID, sessionID)
}

// Activate 激活渠道
func (c *Channel) Activate() {
	c.IsActive = true
	c.LastUsedAt = time.Now()
}

// Deactivate 停用渠道
func (c *Channel) Deactivate() {
	c.IsActive = false
