import (
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"self-agent/channel"
	"self-agent/config"
	"self-agent/session"
)

func main() {
	// 加载配置
	cfg, err := config.LoadConfig()
	if err != nil {
		log.Fatalf("配置加载失败: %v", err)
	}

	// 创建Session
	session := session.NewSession("test-session", cfg.Deepseek.APIKey)

	// 检查是否配置了飞书机器人
	if cfg.HasFeishuConfig() {
		// 创建飞书Channel
		feishuChannel := channel.NewChannel(
			"feishu-bot",
			channel.ChannelTypeFeishu,
			cfg.GetFeishuWebhook(),
			cfg.GetFeishuSecret(),
		)

		// 为Session绑定Channel
		session.SetChannel(feishuChannel)
		fmt.Printf("Session %s 已绑定飞书机器人\n", session.ID)

		// 测试发送消息到飞书
		err := session.SendToChannel("Hello from Self-Agent! Session started.")
		if err != nil {
			log.Printf("发送消息到飞书失败: %v", err)
		} else {
			fmt.Println("消息已发送到飞书机器人")
		}
	} else {
		fmt.Println("未配置飞书机器人，跳过Channel绑定")
	}

	// 演示HTTP API使用
	demoHTTPAPI()
}

func demoHTTPAPI() {
	fmt.Println("\n=== HTTP API 使用示例 ===")

	// 示例1: 绑定Channel到Session
	fmt.Println("1. 绑定Channel到Session:")
	bindData := map[string]interface{}{
		"session_id": "demo-session",
		"channel_type": "feishu",
		"webhook_url": "https://open.feishu.cn/open-apis/bot/v2/hook/your-webhook-id",
		"secret": "your-secret",
	}
	jsonData, _ := json.MarshalIndent(bindData, "", " ")
	fmt.Printf("PUT /ai\n%s\n\n", string(jsonData))

	// 示例2: 发送消息到AI并转发到Channel
	fmt.Println("2. 发送消息到AI并转发到Channel:")
	messageData := map[string]interface{}{
		"id": "demo-session",
		"content": "你好，请介绍一下你自己",
	}
	jsonData, _ = json.MarshalIndent(messageData, "", " ")
	fmt.Printf("POST /ai\n%s\n", string(jsonData))

	fmt.Println("\n响应示例:")
	response := map[string]interface{}{
		"status": "success",
		"session_id": "demo-session",
		"has_channel": true,
	}
	jsonData, _ = json.MarshalIndent(response, "", " ")
	fmt.Println(string(jsonData))
}

// HTTP客户端示例
func sendHTTPRequest() {
	// 绑定Channel
	bindReq := map[string]interface{}{
		"session_id": "test-session",
		"channel_type": "feishu",
		"webhook_url": "your-feishu-webhook",
		"secret": "your-secret",
	}

	jsonData, _ := json.Marshal(bindReq)
	resp, err := http.NewRequest("PUT", "http://localhost:19100/ai", bytes.NewBuffer(jsonData))
	if err != nil {
		log.Printf("绑定Channel请求失败: %v", err)
		return
	}
	resp.Header.Set("Content-Type", "application/json")

	// 发送消息
	messageReq := map[string]interface{}{
		"id": "test-session",
		"content": "Hello, AI!",
	}
	jsonData, _ = json.Marshal(messageReq)
	resp, err = http.NewRequest("POST", "http://localhost:19100/ai", bytes.NewBuffer(jsonData))
	if err != nil {
		log.Printf("发送消息请求失败: %v", err)
		return
	}
	resp.Header.Set("Content-Type", "application/json")
}","instruction":"创建Channel使用示例文件，包含Session绑定Channel的代码示例和HTTP API使用说明","apply_mode":"apply_only"}},"timestamp":1773320104,"type":"TOOL_CALL_ARGS"}

