import (
	"fmt"
	"os"
	"gopkg.in/yaml.v3"
)

// Config 应用配置结构体
type Config struct {
	Deepseek struct {
		APIKey string `yaml:"api_key"`
	} `yaml:"deepseek"`
	Server struct {
		Port int `yaml:"port"`
	} `yaml:"server"`
	Logging struct {
		Level string `yaml:"level"`
		Format string `yaml:"format"`
	} `yaml:"logging"`
	Feishu struct {
		DefaultWebhook string `yaml:"default_webhook"`
		DefaultSecret string `yaml:"default_secret"`
	} `yaml:"feishu"`
}

// LoadConfig 从YAML文件加载配置
func LoadConfig() (*Config, error) {
	// 读取配置文件
	data, err := os.ReadFile("config/config.yaml")
	if err != nil {
		return nil, fmt.Errorf("读取配置文件失败: %v", err)
	}

	// 解析YAML配置
	var cfg Config
	err = yaml.Unmarshal(data, &cfg)
	if err != nil {
		return nil, fmt.Errorf("解析YAML配置失败: %v", err)
	}

	// 检查必要的配置项
	if cfg.Deepseek.APIKey == "your-deepseek-api-key-here" {
		return nil, fmt.Errorf("请配置有效的Deepseek API密钥")
	}

	return &cfg, nil
}

// LoadConfigWithDefaults 加载配置，如果失败则使用默认值
func LoadConfigWithDefaults() *Config {
	cfg, err := LoadConfig()
	if err != nil {
		fmt.Printf("配置加载失败，使用默认配置: %v\n", err)
		return &Config{
			Server: struct {
				Port int `yaml:"port"`
			}{Port: 19100},
			Logging: struct {
				Level string `yaml:"level"`
				Format string `yaml:"format"`
			}{Level: "info", Format: "text"},
			Feishu: struct {
				DefaultWebhook string `yaml:"default_webhook"`
				DefaultSecret string `yaml:"default_secret"`
			}{DefaultWebhook: "", DefaultSecret: ""},
		}
	}
	return cfg
}

// HasFeishuConfig 检查是否配置了飞书机器人
func (c *Config) HasFeishuConfig() bool {
	return c.Feishu.DefaultWebhook != ""
}

// GetFeishuWebhook 获取飞书webhook地址
func (c *Config) GetFeishuWebhook() string {
	return c.Feishu.DefaultWebhook
}

// GetFeishuSecret 获取飞书secret
func (c *Config) GetFeishuSecret() string {
	return c.Feishu.DefaultSecret
}"}

