	// 绑定Channel
	bindReq := map[string]interface{}{
		"session_id": "test-session",
		"channel_type": "feishu",
		"webhook_url": "your-feishu-webhook",
		"secret": "your-secret",
	}

	jsonData, _ := json.Marshal(bindReq)
