package session

import (
	"self-agent/agent"
	"self-agent/model"
)

// Session 会话
type Session struct {
	ID    string
	Tasks model.TaskQueue
	Agent *agent.Agent
}

// NewSession 创建会话
func NewSession(key string, apiKey string) *Session {
	return &Session{
		ID:    key,
		Tasks: model.TaskQueue{},
		Agent: agent.NewAgent(apiKey),
	}
}
